window.SORA_MERCADOS = [{"area":"Lake Chapala / Ajijic (Jalisco)","country":"Mexico","buyerType":"US & Canadian retirees (incl. heavy snowbird/seasonal contingent)","foreignPresence":"Among the densest expat concentrations in the world: ~15,000-20,000 full-time US/Canadian retirees lakeside, roughly doubling to 30,000+ in winter (Lake Chapala Society, International Living, Live & Invest Overseas estimates). In Ajijic proper (~11,500 pop.) foreigners are ~20-40% of residents. No official census, but multiple independent sources converge on the same range.","pricePoint":"~$150k-$400k typical; modest homes/condos from ~$120k, lakeside villas $400k-$700k+","whyForeignersBuy":"Near-perfect year-round spring climate, very low cost of living, decades-deep English-speaking retiree infrastructure, 30-min to Guadalajara airport/hospitals, inland (no fideicomiso needed).","demandSignal":"Active Lake Chapala Society (~3,000+ members), dense Facebook/expat groups, perennial top-of-list in International Living/Live & Invest Overseas retiree rankings, established bilingual realtor ecosystem.","evidenceStrength":"strong"},{"area":"Los Cabos / San Jose del Cabo (Baja California Sur)","country":"Mexico","buyerType":"US (and Canadian) second-home & luxury investment buyers; mostly cash","foreignPresence":"~82% of foreign buyers are US residents (mirrors ~82% US share of arrivals at Los Cabos airport). Foreign-buyer-driven luxury market: Q1 2025 closed ~$878M volume (+24% YoY), with 77% of dollar volume in $1M+ properties. Cash-dominated, distinguishing it from credit-driven US markets. Source: local broker market reports (Oceanside/Brady Thomas Rice).","pricePoint":"San Jose del Cabo avg ~$1.38M; broad market avg home ~$727k-$1.6M, condos ~$615k-$793k; entry homes $300k-$1.2M","whyForeignersBuy":"Beachfront/desert luxury, direct US flight access, golf/resort lifestyle, strong rental yields, established high-end developer pipeline.","demandSignal":"Inventory surged from ~1,100 to 2,500+ listings (2024->mid-2025) and rising price reductions — signals abundant transactional activity now tilting to a buyer's market; double-digit BCS price appreciation (13.1% YoY Q2 2025).","evidenceStrength":"strong"},{"area":"Panama City – Costa del Este, Punta Pacifica & Casco Viejo","country":"Panama","buyerType":"Wealthy/investor expats, multinational executives, North American HNW buyers, digital nomads (Casco STR)","foreignPresence":"Backed by harder data than the beach/mountain towns: Qualified Investor Visa approved 237 apps through Sept 2025 (96% approval); North Americans now the #1 applicant nationality (overtook Colombians); govt scaling from ~25 to 150 investor visas/month. Panama processed 40% more residency apps in H1 2025 YoY. Real estate is the most-used QIV route ($300k threshold).","pricePoint":"Costa del Este ~$2,300-$3,685/m² (median home ~$607k, entry ~$155k); Punta Pacifica ~$3,400-$5,000/m² (2BR ~$370k-$500k); Casco Viejo restored units ~$2,720-$4,150/m², $280k-$1.2M+","whyForeignersBuy":"Investor-visa pathway ($300k), Johns Hopkins-affiliated hospital (Punta Pacifica), modern infrastructure, dollarized, territorial tax, Casco STR/digital-nomad yields and 10-yr tax incentives (now extended to Santa Ana via Ley 519, 2026).","demandSignal":"QIV applicant data showing North American dominance; 40% YoY jump in residency apps (H1 2025); Casco ADRs $130-$180/night (highest in Panama) and tourism arrivals +8% H1 2025; most liquid resale market (Costa del Este). Caveat: luxury oversupply — Santa Maria -6%, Punta Pacifica -2% in 2025; foreigners often overpay 5-15%.","evidenceStrength":"strong"},{"area":"Guanacaste \"Gold Coast\" — Tamarindo, Playa Flamingo, Playas del Coco, Playa Conchal","country":"Costa Rica","buyerType":"US/Canadian vacation/second-home buyers, retirees, and luxury investors; also French, German, Italian, Argentine buyers","foreignPresence":"Highest concentration of American property owners in the country per multiple brokerage and relocation sources. Macro anchor: IOM/DGME data show US nationals = ~5% of all ~582,000 residencies (2nd-largest nationality after Nicaraguans); est. 70,000-120,000+ Americans nationwide, disproportionately clustered here and in the Central Valley. Area-level foreign-buyer share is not officially published (anecdotal/brokerage).","pricePoint":"Condos $100K-$500K; standard 3BR homes $250K-$500K; luxury beachfront/oceanfront $1M-$2M+ (Guanacaste posted the country's highest median listing price ~$1.32M in mid-2025)","whyForeignersBuy":"Dry sunny \"Gold Coast\" climate, Liberia international airport (LIR) access, mature expat infrastructure, strong vacation-rental yields, full foreign-ownership rights","demandSignal":"Guanacaste registered the highest average prices nationwide (mid-2025: ~$2,990/m² apartments, ~$1,582/m² houses); heavy JamesEdition/Coldwell Banker/RE-MAX listing inventory; airport expansion and road projects; 5-yr growth projected 30-50% by brokers; medium-term (28-90 day) digital-nomad rental demand","evidenceStrength":"strong"},{"area":"Cuenca (El Centro, Gringolandia/Av. Ordóñez Lasso, Puertas del Sol, Challuabamba)","country":"Ecuador","buyerType":"US and Canadian retirees (plus some Europeans); modest digital-nomad/remote-worker tail","foreignPresence":"~8,000-10,000 expats, of whom roughly 4,000-8,000 are Americans. Corroborated across multiple sources: local paper El Tiempo cited >8,000 Americans by 2015 (12,000 incl. Canadians/Europeans); Cuenca mayor estimated ~4,000 Americans; Wikipedia 'Americans in Ecuador' cites 5,000-10,000 nationally clustered in Cuenca. Numbers are estimates (no official registry), but this is the only Ecuadorian area with consistent multi-source expat counts and dedicated expat-buyer infrastructure.","pricePoint":"City-center condos ~$117/sq ft; typical expat condo $150k-$250k (Puertas del Sol from ~$245k); free-standing homes in Challuabamba ~$350-400/m2; luxury apartments from ~$230k, hard to find anything over $1M","whyForeignersBuy":"Lowest cost of living among proven hubs (couples on $1,600-2,000/mo), spring-like Andean climate, UNESCO colonial core, and uniquely it is the safest large city in South America (1.4 homicides/100k in H1 2025) while the rest of Ecuador is in a crime crisis","demandSignal":"Dedicated expat real-estate portals (ExpatsEcuador, CuencaHighLife buying guides), active expat forums, recurring #1 'best place to retire' rankings, $42.5k-$48k real-estate investor visa pathway widely used. No evidence of an expat exodus despite national security headlines.","evidenceStrength":"strong"},{"area":"Ambergris Caye / San Pedro","country":"Belize","buyerType":"US & Canadian retirees and 40s-50s lifestyle/second-home buyers; also rental investors","foreignPresence":"Estimated 2,000-2,500 foreign expats (largest island expat hub); local real-estate agents estimate 90-95% of buyers on the island are foreigners, overwhelmingly American and Canadian. Note: the 90-95% figure is agent-reported, not an official transaction statistic.","pricePoint":"Condos avg ~$460K (entry ~$135-290K), single-family homes avg ~$940K, beachfront estates $2M+ (USD)","whyForeignersBuy":"Caribbean beachfront, English-speaking, freehold foreign ownership with no restrictions, no capital gains tax, most developed expat infrastructure in the country","demandSignal":"Tightest inventory in Belize with 30-60 day sale times and multiple-offer situations; reported 9-14% YoY price appreciation; heavy MLS/portal listing volume; International Living and Live & Invest Overseas flagship destination; documented surge in US/Canadian inquiries 2020-2022","evidenceStrength":"strong"},{"area":"Punta Cana / Cap Cana / Bávaro (La Altagracia, East Coast)","country":"Dominican Republic","buyerType":"US/Canadian vacation & second-home buyers and yield-focused investors; some retirees","foreignPresence":"Highest concentration of foreign buyers in the country per multiple realtor/market sources; part of the ~14,600 US/Canadian residents clustered across PC, Puerto Plata, Sosua, Cabarete and Las Terrenas. National real-estate transactions grew ~20%/yr 2020-2023 led by US/Canada buyers. No official foreign-buyer-share registry exists (DR has no public sales-record system), so area-level shares are realtor-derived.","pricePoint":"Condos ~$100k (studio) to $245k typical; beachfront Cap Cana units $400k+; villas $525k+; lots ~$300k","whyForeignersBuy":"Resort infrastructure, international airport (PUJ), strongest short-term rental market, gated-community safety, and CONFOTUR 15-yr tax exemption","demandSignal":"11.8M tourists 2025, ~10.7% YoY apartment price growth (May 2025), heavy CONFOTUR new-build pipeline, dense portal listings and STR/Airbnb demand; consistently #1 in DR realtor market reports","evidenceStrength":"strong"},{"area":"Las Terrenas / Samaná Peninsula (Northeast)","country":"Dominican Republic","buyerType":"European expats/retirees (French, Italian, German) historically; North Americans/Canadians now ~30% of current sales","foreignPresence":"Documented ~6,000 full-time + ~5,000 part-time expats from 23+ countries in a town of ~30k; 30+ year established French community with real expat infrastructure (schools, bistros, businesses). This is a stable resident base, not a tourist crowd — among the best-evidenced genuine expat hubs in DR.","pricePoint":"Town-center condos $180k-$300k; beachfront condos from ~$200k; Playa Bonita/Cosón luxury villas $400k-$1M+ (vs $1.2M equivalents in Barbados)","whyForeignersBuy":"Euro-village lifestyle, walkable town, beaches, materially cheaper than Tulum/Barbados/Costa Rica, established European community, CONFOTUR","demandSignal":"Documented buyer-group breakdown (French largest, Italian second, North American fastest-growing $300k+), year-round rental demand from European home networks, ~75% occupancy claims (agency-sourced), El Catey international airport","evidenceStrength":"strong"},{"area":"Punta del Este + satellites (La Barra, Manantiales, José Ignacio)","country":"Uruguay","buyerType":"Vacation/second-home and investor buyers — overwhelmingly Argentine (~75%) and Brazilian (~20%), with a small but growing North American and European (German/Swiss/Austrian) high-end contingent","foreignPresence":"HARD DATA: In premium coastal segments (La Barra, José Ignacio, Manantiales) foreign buyers = 30-66% of transactions depending on price band; ~75% of high-end luxury buyers are foreign (Global Property Guide / agency data). BUT North Americans + Europeans are only ~5% of ALL foreign buyers nationally — so the genuine NA/EU slice here is thin in absolute numbers, concentrated in trophy assets.","pricePoint":"Punta del Este peninsula ~$5,000/m2; beachfront $7,000-10,000/m2; most deals $200k-400k. La Barra/Manantiales ~$3,500-4,000/m2. José Ignacio avg listing ~$4M, villas $600k to $10M+; luxury homes $2M-6M core","whyForeignersBuy":"Dollar-denominated assets, no capital gains tax for foreigners, political stability/safety, exclusivity and scarcity (strict building limits in José Ignacio), 8-12% appreciation in prime cores","demandSignal":"Punta del Este prices +~10% YoY mid-2025; José Ignacio/La Barra +25% over 3 yrs; Uruguay closed 2025 with USD 2.7B in property transactions (INE); heavy JamesEdition/portal luxury listings. Demand is real but Argentina/Brazil-driven, not NA/EU-driven","evidenceStrength":"strong"},{"area":"Montevideo — Pocitos, Punta Carretas, Carrasco","country":"Uruguay","buyerType":"Relocating professionals, European retirees, digital nomads, and the largest concentration of actual North American expat homeowners in the country","foreignPresence":"HARD DATA: Montevideo handles ~80% of all national real-estate transactions; Pocitos, Punta Carretas and Carrasco are the documented top neighborhoods for US expat homeowners. In premium Carrasco, foreign buyers = 30-66% of deals. Calibration: total US-born in Uruguay ~2,800-2,900 (census), 616 US residency applications in 2025 (double prior year) — so the NA expat base is real but in the low thousands, not a mass market","pricePoint":"Well-located 2BR in Pocitos ~$150k-200k; coastal premium neighborhoods among the most expensive in country; cheaper inland barrios (Reducto) $80k-120k (~$1,525/m2)","whyForeignersBuy":"Urban services, top healthcare/education, rambla waterfront lifestyle, liquid resale market, 5-12% rental yields, rule of law and easy foreign ownership","demandSignal":"Most liquid market in Uruguay; rising US residency applications (616 in 2025, 2x YoY); steady rental demand; portal depth on Infocasas/Mercado Libre/Gallito. The NA/EU growth trend is genuine but off a small base","evidenceStrength":"strong"},{"area":"Buenos Aires – Palermo (Soho/Hollywood/Chico)","country":"Argentina","buyerType":"Digital nomads, remote workers, younger lifestyle expats, US/European investors and second-home buyers","foreignPresence":"Argentina has ~60,000 US expats (many in BA); CABA foreign-born ~5-6% (>150k in metro, INDEC). Palermo is repeatedly named the #1 expat/foreign-buyer neighborhood. Hard transaction signal: real-estate agencies estimate ~8% of 2025 CABA purchases came from foreign capital (El Cronista), up from ~0% a year earlier, against 69,461 total CABA transactions in 2025 (Colegio de Escribanos, +27% YoY). Note: notaries do NOT officially break out buyer nationality, so the 8% is an industry estimate, not registry data.","pricePoint":"~$2,000-4,000/m2; typical foreign purchase ~$120,000-300,000 (≈80% of BA deals fall $80k-250k)","whyForeignersBuy":"Trendy, walkable, European feel, dense expat/nomad scene, short-term-rental income potential, prices ~28% below 2020 peak in USD","demandSignal":"Most-cited expat neighborhood across guides; large nomad/expat Facebook + InterNations communities; portal listings concentrated here; agencies report foreigner-driven demand surge in 2025 under Milei reforms","evidenceStrength":"strong"},{"area":"Buenos Aires – Recoleta","country":"Argentina","buyerType":"Older/retiree expats, European buyers, lifestyle and capital-preservation investors","foreignPresence":"Consistently named alongside Palermo as the top neighborhood for American/European expats. Part of the CABA market where ~8% of 2025 transactions were foreign-capital (El Cronista estimate). No neighborhood-level nationality registry exists; presence is well-attested in expat surveys/guides but not in official per-barrio data.","pricePoint":"~$2,500-4,500/m2; typical foreign purchase ~$150,000-350,000","whyForeignersBuy":"Belle-Époque 'Paris of South America' architecture, prestige address, safety, central location, strong USD value after the downturn","demandSignal":"Top-named expat barrio in multiple 2026 guides; high foreign-facing agency listing volume; favored by retiree-visa (rentista/pensionado) holders","evidenceStrength":"strong"},{"area":"Puerto Vallarta / Riviera Nayarit (Jalisco-Nayarit Pacific)","country":"Mexico","buyerType":"US & Canadian retirees, LGBTQ+ buyers, second-home/vacation-rental investors, digital nomads","foreignPresence":"Mature, decades-established expat community (no single hard census number, but consistently cited as one of Mexico's largest coastal expat hubs). Strong year-round + snowbird population; Zona Romantica is a recognized US/Canadian + LGBTQ+ enclave. Evidence is largely market/broker + portal based rather than a clean census count.","pricePoint":"Condos ~$200k-$500k; beachfront/hillside villas $500k-$2M+","whyForeignersBuy":"Beach + mountains, deep bilingual infrastructure, direct flights, long rental season for cash flow, established LGBTQ+-friendly reputation.","demandSignal":"Long high-occupancy rental season cited by brokers, heavy short-term-rental listing volume (now facing new STR regulation), steady predictable appreciation; broad bilingual realtor/portal presence.","evidenceStrength":"moderate"},{"area":"San Miguel de Allende (Guanajuato)","country":"Mexico","buyerType":"Affluent US & Canadian retirees, artists, lifestyle/second-home buyers","foreignPresence":"One of the highest proportional concentrations of foreign property owners in Mexico — roughly ~10% of residents are foreigners (UNESCO World Heritage colonial city). Long-standing American artist/retiree community. Hard headcount is fuzzy, but the foreign-owner share is repeatedly cited and historically deep.","pricePoint":"Restored colonial homes commonly $350k-$1M+; premium/historic-center properties $1M-$3M+","whyForeignersBuy":"Colonial architecture, arts scene, temperate climate, prestige, inland (direct ownership, no fideicomiso), scarcity of prime historic stock.","demandSignal":"Repeatedly ranked a top global small city (Travel+Leisure/Condé Nast), thriving high-value Airbnb segment, premium-priced scarcity-driven listings.","evidenceStrength":"moderate"},{"area":"Merida (Yucatan)","country":"Mexico","buyerType":"US & Canadian retirees + remote workers; growing German/French interest; investors","foreignPresence":"~10,000 US/Canadian expats now resident (cited across multiple independent sources). Yucatan region reportedly 40-50% of buyers from outside the area. Inland — no fideicomiso. The ~10k figure and ~15% 2025 price growth recur across sources; some appreciation claims come from marketing sites and should be discounted.","pricePoint":"Houses avg ~$250k (4.8M MXN), apartments ~$150k; restored Centro colonials and north-city new builds span ~$150k-$400k+","whyForeignersBuy":"Consistently ranked Mexico's safest city, low cost vs. US (homes 30-60% cheaper than comparable US cities), colonial Centro charm, Maya Train infrastructure upside, inland direct ownership.","demandSignal":"~15% YoY price growth in 2025; 25k-30k new residents/yr; concentrated expat settlement in Centro Historico and north Merida; active Yucatan-focused realtor/portal ecosystem — though now maturing (homes closing 3-7% below ask).","evidenceStrength":"moderate"},{"area":"Coronado (Pacific 'City Beach' coast, Coclé/Panamá Oeste)","country":"Panama","buyerType":"US/Canadian retirees + Panamanian second-home owners; some Europeans","foreignPresence":"Community estimates of ~5,000+ residents with a 'large' expat share (mix of US, Canadian, European); cited by Retire in Panama Tours/expat sources. No official census split — figures are relocation-industry estimates, not transaction data.","pricePoint":"~$180,000-$450,000 for condos and houses; beachfront/larger homes $500k+","whyForeignersBuy":"Closest fully-built beach retiree town to Panama City (~1hr), turnkey amenities, US-style supermarkets/medical, dollarized, Pensionado-friendly.","demandSignal":"Consistently named the #1 beach expat town across multiple relocation sources; dense expat infrastructure (English services, expat associations); steady resale market near the capital.","evidenceStrength":"moderate"},{"area":"Boquete (Chiriquí Highlands)","country":"Panama","buyerType":"US/Canadian retirees building/buying custom mountain homes; some European","foreignPresence":"Most-cited estimate: ~5,000 expats out of ~25,000 residents (one of Panama's oldest and largest expat communities). Source is relocation/tour companies (Retire in Panama Tours, International Living), not official census; treat as approximate.","pricePoint":"~$200,000-$600,000 for developed lots/homes with mountain or valley views","whyForeignersBuy":"Spring-like climate year-round, lowest-cost cool-climate option, established English-speaking retiree community, Pensionado visa.","demandSignal":"Panama's flagship 'original' expat town; perennial top ranking in International Living and relocation media; mature real-estate brokerage presence catering to foreigners.","evidenceStrength":"moderate"},{"area":"Pedasí (Los Santos, Azuero Peninsula)","country":"Panama","buyerType":"US/Canadian/European retirees + growing remote workers; mostly cash buyers","foreignPresence":"Several hundred expats within a town of just under 5,000 (relocation-source estimate). Casa Solution's 2025 market report describes 'robust' transaction growth in named communities (Costa Pedasí, Roy's Project, Haciendas del Toro) but gives no hard buyer counts.","pricePoint":"Buildable ocean-view lots and homes; modern 3BR ocean-view homes rent $1,500-$2,500/mo (sale prices broadly mid-six-figures, value still in land)","whyForeignersBuy":"Quiet beach/surf town, affordable, safe, Pensionado-friendly; cash-buyer base insulates it from financing swings.","demandSignal":"Broker market reports cite rising 2025 sales volumes and depleted luxury beachfront inventory at Los Destiladeros; smaller but genuinely active foreign-buyer niche. Evidence is broker-sourced, not independent.","evidenceStrength":"moderate"},{"area":"Central Valley — Escazú, Santa Ana, Atenas, Grecia, San Ramón","country":"Costa Rica","buyerType":"US/Canadian retirees (pensionado/rentista), corporate transferees and families (Escazú/Santa Ana), lifestyle migrants","foreignPresence":"Long-established, decades-old expat base; the Central Valley holds ~two-thirds of CR's population and a large share of full-time (vs. vacation) foreign residents. Atenas flagged by AARP (2010) as a top retire-abroad spot. Foreign population is real and resident-heavy but not quantified per-town in official stats.","pricePoint":"Escazú/Santa Ana homes $150K-$400K+ ($1,000-$1,500/m²); Western Valley (Atenas, Grecia, San Ramón) $600-$1,000/m², homes meaningfully cheaper","whyForeignersBuy":"Year-round spring-like climate at altitude (no A/C needed), proximity to SJO airport, top private hospitals (CIMA, Clínica Bíblica), bilingual schools, lower cost of living (~$2,000/mo for a couple)","demandSignal":"Established AutoMercado/PriceSmart/expat-network infrastructure; Atenas and Grecia projected 5-8% growth on lifestyle migration + SJO proximity; consistently cited as the practical full-time-living hub vs. coastal second-homes","evidenceStrength":"moderate"},{"area":"Nicoya Peninsula surf/wellness coast — Nosara & Santa Teresa / Mal País","country":"Costa Rica","buyerType":"Affluent US/European wellness buyers, surfers, digital nomads, younger families, retreat operators","foreignPresence":"Dense, visible international/expat communities (Nosara Guiones, Santa Teresa) — but presence is documented mainly via brokerage and portal data, not census/visa figures. Nosara's Guiones is an expat-dominated enclave; Santa Teresa is majority-international in its core market per agency reports.","pricePoint":"Nosara $300K-$2.5M+ (most expensive beach market; $1M buys 180-280m² ocean/jungle home); Santa Teresa luxury averages ~$2.0M, villas $1.5M-$5M+, ocean-view homes $500K-$2M","whyForeignersBuy":"Nicoya Blue Zone status, world-class surf, yoga/wellness culture, strong short-term rental yields (7-12% on ocean-view STRs; 80%+ peak-season occupancy), digital-nomad visa appeal","demandSignal":"Digital-nomad visa applications +20% in 2025 (mostly North America/Europe); strong medium-term rental demand; BUT 2024-25 correction of 15-25% on some Nosara/Santa Teresa listings with rising inventory and longer days-on-market — i.e., real demand cooling from a hyped peak","evidenceStrength":"moderate"},{"area":"Central Pacific — Jacó & Manuel Antonio/Quepos","country":"Costa Rica","buyerType":"US vacation/second-home buyers, weekend-home owners from San José, short-term-rental investors","foreignPresence":"Established foreign-owner presence tied to the oldest mass-tourism corridor on the Pacific (closest beaches to San José/SJO). Presence is real and infrastructure-backed but quantified only anecdotally/by brokerages.","pricePoint":"Condos from ~$150K; homes commonly $250K-$500K; luxury Manuel Antonio oceanfront $1M-$2M+","whyForeignersBuy":"Closest beach to the capital and SJO airport, mature tourism infrastructure, Manuel Antonio national-park draw driving consistent rental demand, easy entry-level price points","demandSignal":"Strong seasonal STR occupancy (70-90% peak in Jacó/Manuel Antonio); steady tourist-arrival-driven price support; deep brokerage inventory (Coldwell Banker Jacó). Less luxury/cachet than Guanacaste, more transactional","evidenceStrength":"moderate"},{"area":"Medellín – El Poblado & Laureles (incl. Envigado, Sabaneta)","country":"Colombia","buyerType":"US/Canadian retirees + digital nomads; secondary European; some investors buying-to-rent","foreignPresence":"Most-cited foreign-buyer hub in Colombia. No official nationality-segmented buyer data exists (confirmed: Banco de la República only tracks FDI via Form 4, not buyer nationality). Estimates are anecdotal/expat-source: expats concentrate heavily in El Poblado (Provenza, Manila, Castropol) and Laureles; Americans are 'a small share of national transactions but very visible' locally. Colombia issues thousands of M-pensionado and digital-nomad visas/yr nationally, with Medellín the #1 destination. Treat headcounts as estimates, not census.","pricePoint":"1-bed Laureles/Envigado $55K–$90K; furnished El Poblado studios $70K–$130K; premium El Poblado towers $150K–$350K+","whyForeignersBuy":"Spring-like climate, walkability, English-friendly services, established expat critical mass, metro access, prices still below Bogotá with 5–9% gross rental yields","demandSignal":"Largest English-speaking real-estate-agency ecosystem in Colombia (Medellin Guru, multiple foreigner-focused brokerages), dense Facebook/WhatsApp expat groups, strong STR/Airbnb demand in Provenza (now causing rent inflation and gentrification pushback), highest portal-listing volume targeting foreigners","evidenceStrength":"moderate"},{"area":"Cartagena – Bocagrande, Castillogrande & El Laguito (+ Centro Histórico/Getsemaní)","country":"Colombia","buyerType":"US/Canadian + Spanish/European vacation & second-home buyers; investors; wealthy Latin Americans; diplomats","foreignPresence":"~70% of foreign buyers in Cartagena concentrate in Bocagrande/Castillogrande/El Laguito (broker-reported, TheLatinvestor). Largest expat origin groups: US, Canada, Spain, other Europe, plus Venezuelans. The single most-named city of interest for foreign buyers in multiple guides. No official foreign-buyer-share figure published.","pricePoint":"1-bed from ~$200K; 3-bed ~$500K (≈140 m² Bocagrande); penthouses $1M+; Bocagrande $2,000–$3,500/m², Old City $3,000–$5,000/m²","whyForeignersBuy":"Caribbean beachfront + colonial UNESCO old city, cosmopolitan luxury, strong USD purchasing power, 60–70% cheaper than comparable US/EU beach cities, 5–9% STR yields in peak season","demandSignal":"High share of foreign-targeted luxury listings (LuxuryLatinAmerica, Properstar), active short-term-rental market — though authorities are tightening RNT/Airbnb enforcement and many towers now ban STR. Caveats: high salt-air HOA fees, aging buildings, traffic.","evidenceStrength":"moderate"},{"area":"Coast: Salinas, Manta/San Clemente, Olón–Montañita","country":"Ecuador","buyerType":"Vacation/second-home buyers, some North American retirees, short-term-rental investors","foreignPresence":"No hard expat counts published; demand is real but anecdotal. Manta is cited as having a 'significant expat population' with good air links, and the national US expat community (~10,000) is described as clustering partly in beach city Salinas. Evidence is portal- and developer-driven rather than census/transaction-backed.","pricePoint":"Salinas oceanfront condos $80k-$250k; Manta/San Clemente condos $50k-$150k (cheapest coast value); Olón–Montañita houses $60k-$200k (3-story height cap, no high-rises)","whyForeignersBuy":"Beachfront at a fraction of Costa Rica/Panama prices, dollarized economy (no FX risk), STR/Airbnb income, and remote-work lifestyle","demandSignal":"Surge in beachfront listings and STR activity on portals (OverseasRealty, EcuadorHomeSales); remote-work-driven interest. BUT major counter-signal: Manabí, Guayas, El Oro and Esmeraldas coastal provinces account for ~88% of Ecuador's murders (national rate ~51/100k in 2025), which suppresses serious foreign-buyer demand and makes much of the marketing hype.","evidenceStrength":"moderate"},{"area":"Quito valleys – Cumbayá, Tumbaco, Valle de los Chillos","country":"Ecuador","buyerType":"Embassy/NGO staff, multinational executives, diplomats — predominantly RENTERS; relatively few foreign owner-occupiers","foreignPresence":"Real international presence but dominated by affluent Ecuadorians; the foreign component is mostly transient professionals who rent rather than buy. No published foreign-buyer share or expat population count for the valleys specifically.","pricePoint":"3-bed home in Cumbayá/Tumbaco $180k-$350k; 2-bed Quito apartments (La Carolina/González Suárez) $85k-$160k; ~$1,330/m2 city average","whyForeignersBuy":"Warmer/lower-elevation suburb 20 min from Quito, international schools (USFQ), gated security, capital-city amenities; landlords see 6-7% gross rental yields from the expat-executive rental pool","demandSignal":"Strong upscale rental market for expats and premium price appreciation in Cumbayá; but a sober counter-signal that Quito condos often depreciate long-term ('like buying a car'), and the buyer base is Ecuadorian-led, so foreign-BUYER demand is thinner than foreign-renter demand.","evidenceStrength":"moderate"},{"area":"Corozal Town / Corozal District","country":"Belize","buyerType":"Budget-focused US & Canadian retirees (many snowbirds living half the year); pension/savings-based, not investors","foreignPresence":"Frequently cited as the largest (or co-largest) expat community in Belize; estimates range widely from ~600-700 to ~2,000 American/Canadian expats in a town of ~14,000. Figures are anecdotal/agent-estimated, not census-confirmed.","pricePoint":"Homes ~$75K-$300K; oceanfront lots and modest houses at a fraction of island prices (USD)","whyForeignersBuy":"Lowest cost of living, drier climate, English-speaking, and direct access to Chetumal Mexico for cheaper shopping, healthcare and duty-free goods","demandSignal":"Repeatedly ranked for affordable retirement (AARP, International Living 'overlooked cities'); active full-time + snowbird community; rising prices noted even in this budget market; QRP retiree program inflow. Demand is real but lower-velocity and lower-dollar than the coast.","evidenceStrength":"moderate"},{"area":"Placencia Peninsula (Placencia Village, Maya Beach, Plantation)","country":"Belize","buyerType":"US & Canadian retirees, part-time expats, second-home and beachfront-villa buyers, some digital nomads and developers","foreignPresence":"Expat community estimated at ~350 (mostly American, Canadian, European) out of a peninsula population of ~2,000; described as small but active and growing. Estimate is rough/anecdotal.","pricePoint":"2BR condos ~$250-450K; beachfront homes/villas ~$450K-$1.2M+, prime beach houses $700K-$2M (USD)","whyForeignersBuy":"Mainland beach lifestyle quieter than San Pedro, more land for the money, freehold ownership, planned regional international airport boosting development","demandSignal":"Reported 9-14% YoY appreciation, tightening inventory (off-water sub-$400K homes 'getting harder to find'), faster sale cycles (30-60 days vs years a decade ago); strong portal/MLS presence and agent network (RE/MAX, etc.); North American demand cited as primary driver","evidenceStrength":"moderate"},{"area":"Sosúa & Cabarete (Puerto Plata, North Coast)","country":"Dominican Republic","buyerType":"Canadian/US/European retirees (Sosúa) and younger digital nomads / watersports buyers (Cabarete)","foreignPresence":"Long-established (15+ year) expat retiree communities, part of the ~14,600 US/Canadian residents clustered on the north coast; described as seeing the biggest expat growth in 15 years with new 2026 direct flights from Texas, California and Germany. Most concentration figures are realtor-sourced rather than census-verified.","pricePoint":"Cabarete condos ~$175k (villas $408k+); Sosúa condos ~$189k, ocean-view villas under $300k; Costambar homes $190k-$714k","whyForeignersBuy":"Lower entry prices than Punta Cana, laid-back community-focused expat life, watersports (kiteboarding/windsurf), POP airport access, low cost of living (couple $1,800-$2,400/mo)","demandSignal":"Reported 7-9% rental yields, established gated communities (Sea Horse Ranch, Casa Linda), International Living affordability rankings, strong STR demand near POP airport; signals partly inflated by agency marketing","evidenceStrength":"moderate"},{"area":"Santo Domingo – Piantini / Naco / Evaristo Morales / Zona Colonial","country":"Dominican Republic","buyerType":"Latin American investors (Argentine, Colombian, Venezuelan), affluent diaspora, and urban/business expats — fewer NA/European retirees","foreignPresence":"Listed among top expat-concentration neighborhoods, but the foreign cohort skews Latin American capital-flight buyers and business expats rather than North American/European retirees; foreign-buyer share here is the least documented of the major hubs.","pricePoint":"Modern condos roughly $150k-$400k+ in Piantini/Naco luxury towers","whyForeignersBuy":"Capital city amenities, business/economic hub, cultural depth, stable real-estate store-of-value for LatAm investors fleeing volatile home markets","demandSignal":"Named in expat-concentration lists; strong LatAm investment inflows cited; but lacks the dedicated foreign-retiree infrastructure and STR demand of the coastal hubs","evidenceStrength":"moderate"},{"area":"La Romana / Casa de Campo (Southeast)","country":"Dominican Republic","buyerType":"High-net-worth US/European/Latin American luxury second-home buyers","foreignPresence":"Genuine but small, niche ultra-luxury foreign-owner enclave centered on the Casa de Campo resort (golf, marina, private villas); foreign ownership is real but volume is low versus Punta Cana or the north coast — concentration data is anecdotal/developer-sourced.","pricePoint":"Luxury villas commonly $800k to several million; lower-tier condos exist but the draw is high-end","whyForeignersBuy":"Exclusivity, world-class golf/marina, privacy, established prestige resort brand, proximity to La Romana airport","demandSignal":"Steady ultra-luxury resale and resort-brand demand, but thin public data and small transaction volume; mostly developer/luxury-broker copy","evidenceStrength":"moderate"},{"area":"Colonia del Sacramento (Barrio Histórico)","country":"Uruguay","buyerType":"North American / English-speaking expats and retirees, plus Argentine weekend second-home buyers","foreignPresence":"MIXED DATA: Explicitly named among the top areas for American buyers (alongside Pocitos/Punta Carretas/Carrasco and La Barra/Manantiales/Roosevelt). UNESCO heritage core, year-round (not just summer) which sustains an expat community. But no hard count of foreign owners — evidence is qualitative plus agency claims of ~15% YoY price growth that read promotional","pricePoint":"Historic-center character homes $200k-500k; modern apartments/homes outside center cheaper","whyForeignersBuy":"UNESCO colonial charm, open year-round, ferry-close to Buenos Aires, safety, lower entry price than Punta del Este, retiree tax benefits (zero tax on foreign-source income for new residents)","demandSignal":"Named repeatedly as a US/expat hub; International Living and agency coverage; claimed +15% YoY prices (treat agency figures with skepticism). Live demand exists but is modest and partly hype-amplified","evidenceStrength":"moderate"},{"area":"Buenos Aires – Puerto Madero","country":"Argentina","buyerType":"High-net-worth investors, multinational professionals, vacation/second-home buyers","foreignPresence":"Named as a top foreign-buyer zone and the most expensive BA neighborhood; favored by corporate/multinational expats. Foreign share is part of the citywide ~8% agency estimate; no isolated nationality data. Smaller absolute buyer pool than Palermo/Recoleta but disproportionately foreign and investor-driven.","pricePoint":"~$3,500-6,000/m2; typical foreign purchase ~$300,000-700,000+","whyForeignersBuy":"New-build waterfront towers, security, amenities, USD pricing, trophy/investment appeal, easy turnkey for absentee owners","demandSignal":"Premium portal listings target foreign capital; cited as preferred zone for professional/HNW foreign buyers; resilient USD prices","evidenceStrength":"moderate"},{"area":"Mendoza (city, Chacras de Coria, Uco Valley wine country)","country":"Argentina","buyerType":"Wine-lifestyle buyers, retirees, remote workers, agrotourism/boutique-winery investors","foreignPresence":"Real but modest community: 'Mendoza Expat Community' Facebook group ~3,500 members; active InterNations chapter; expats cluster in Chacras de Coria, Centro/Quinta Sección, and Uco Valley. Hard transaction/nationality data is absent — most figures come from commercial sources (TheLatinvestor, Overseas Property Alert, International Living). Working vineyard/rural land purchases face legal uncertainty under the contested Ley 26.737 foreign-ownership caps.","pricePoint":"Apartments from ~$75,000 (~$1,200/m2); vineyard/rural estates $200,000-300,000+","whyForeignersBuy":"Malbec wine-country lifestyle, low cost of living, climate, mountain scenery, agrotourism upside","demandSignal":"Niche expat groups and meetups; wine-estate developer marketing; International Living rankings — but demand is more anecdotal/marketing-driven than data-proven","evidenceStrength":"moderate"},{"area":"Ceará coast – Fortaleza metro + beach towns (Cumbuco, Taíba, Flecheiras, Jericoacoara)","country":"Brazil","buyerType":"European second-home / vacation buyers (Portuguese, Italian, German, French, Scandinavian) and kitesurf/wind-sport crowd; some retirees","foreignPresence":"The strongest proven European beach-buyer base in Brazil, built over ~15 years. Hard data is thin at municipal level, but a widely-cited industry figure claims ~30% of NE Brazil property sales in 2024 went to foreign buyers (developer/portal sourced, treat with caution). Ceará's market moved >R$2.1bn through April 2025, +13% YoY (industry association data). Direct Fortaleza–Lisbon/Paris flights underpin the European pipeline. No official IBGE/OBMigra foreign-resident count published at beach-town level — buyer presence is real but quantified mostly via realtor channels.","pricePoint":"$150k–$500k for beach villas; Cumbuco/Taíba entry villas $150k–$300k, Jericoacoara luxury $400k+; qualifies for R$700k NE Golden Visa threshold","whyForeignersBuy":"365-day sun, reliable trade winds (kitesurf capital), direct Europe flights, low NE prices, R$700k Golden Visa threshold and 30% NE developer discounts","demandSignal":"Dedicated European-facing portals (meretdemeures, Camila Saunier, fortalezaceararealestate, cumbucoproperty), English/Portuguese expat law firms, 2025 sales +13% YoY, 38% rise in international tourists 2024","evidenceStrength":"moderate"},{"area":"Florianópolis, Santa Catarina (Jurerê Internacional, Lagoa da Conceição, Campeche)","country":"Brazil","buyerType":"Digital nomads and lifestyle expats; South American neighbors (Argentina, Uruguay) dominate, plus Portugal, Germany, US","foreignPresence":"Best government-backed data of any Brazilian expat hub: OBMigra registrations and IBGE 2022 Census show steady but still small absolute foreign inflows to Santa Catarina, led by Argentines/Uruguayans under Mercosur, not North Americans/Europeans. FIPEZAP (Dec 2025) avg ~R$12,770/m² (~$2,365), one of Brazil's priciest markets, +11% in 2024. North American/European foreign-BUYER share specifically is not quantified and appears modest.","pricePoint":"~$2,365/m²; apartments commonly $250k–$700k+, beachfront/Jurerê luxury well above","whyForeignersBuy":"Highest quality-of-life ranking in Brazil, beaches, safety, tech sector, digital-nomad visa (2022) appeal","demandSignal":"FIPEZAP price index, OBMigra inflow data, strong appreciation (5.5% 2023, 11% 2024), heavy digital-nomad/expat-guide coverage","evidenceStrength":"moderate"},{"area":"Lima – Miraflores, Barranco & San Isidro","country":"Peru","buyerType":"Affluent US/European/expat professionals, some retirees, returning diaspora and Lima-based foreign workers; lifestyle + rental-yield investors","foreignPresence":"HARD DATA: Peru has ~14,101 resident US nationals, ~13,804 Spaniards, ~3,860 Italians as of Sept 2023 (INEI/Migraciones nationality breakdown). The US Embassy in Lima estimates the American community grew ~15-20% since 2020. These Western residents cluster disproportionately in Lima's prime districts (Miraflores, Barranco, San Isidro). NOTE: Peru's headline 1.35M foreigners are 85.7% Venezuelan economic migrants — renters/workers, NOT home-buyers — so the real buyer pool is the ~30-40k Western residents, mostly in Lima.","pricePoint":"~$2,100-$3,630/m² in prime districts (Urbania/BCRP Q3-Nov 2025); typical quality units ~$239k (100m² Barranco) to ~$363k (150m² San Isidro El Golf); luxury $800k-$2.5M","whyForeignersBuy":"Modern infrastructure, world-class food/nightlife, coastal Malecón lifestyle, biggest established expat community, USD-denominated market, ~4-5% rental yields","demandSignal":"Most listings/coverage on Urbania, GlobalPropertyGuide and portal data; prime districts lead price appreciation (+4% nominal YoY); Miraflores hotels ~90% foreign guests; largest US-resident concentration in the country","evidenceStrength":"moderate"},{"area":"Cusco & Sacred Valley (San Blas, Pisac, Urubamba)","country":"Peru","buyerType":"Bohemian/spiritual/wellness expats, digital nomads, Airbnb short-term-rental investors; a 'happy hippy' expat community in Pisac plus tourism-rental buyers in Cusco","foreignPresence":"ANECDOTAL/SMALL: Migraciones lists Cusco as one of the top-three US-expat concentrations after Lima, but no hard headcount. Sacred Valley expat presence is real but small — dedicated infra (Sacred Valley Expats, Sacred Valley Realty in Urubamba, active FB groups) confirms a community, not numbers. No published foreign-buyer share.","pricePoint":"Cusco citywide ~$700-$1,200/m² (San Blas above average); Sacred Valley land/homes vary widely, often cash deals under $150k","whyForeignersBuy":"Machu Gateway tourism, year-round Airbnb demand, low cost, cultural/spiritual draw, agricultural land for self-sufficiency","demandSignal":"Active expat-run real-estate sites and large Facebook housing groups; strong short-term-rental/tourism economics; nomads increasingly base in Pisac over San Blas","evidenceStrength":"moderate"},{"area":"San Juan del Sur (SJDS), Rivas department — Pacific coast","country":"Nicaragua","buyerType":"North American & European vacation/second-home buyers, surfers, younger digital nomads, some retirees","foreignPresence":"Most-cited estimate ~1,000-1,200 expats in/around SJDS (town pop ~16,000), per local real-estate/expat sources; demographic skews young (only ~5-10% retiree-age). No official census — figures come from brokers and expat guides, treat as approximate. ~10% own a second home elsewhere and live seasonally.","pricePoint":"~$150K for a nice 2BR, ~$200K for a 3BR with pool; beachfront villas $500K-$1M+; developed beachfront lots $100K+","whyForeignersBuy":"Established beach/surf town with bay, restaurants, two international schools and the densest expat services in the country; prices a fraction of Costa Rica/Panama","demandSignal":"Active broker market (RE/MAX, BVN, Discover, Malibu Nicaragua) with steady listings; brokers report 6-10% price growth in 2025-26 tied to the ~$400M Costanera coastal highway; cash-dominant transactions; recovering from a ~30% USD price crash after the 2018 unrest","evidenceStrength":"moderate"},{"area":"Granada — colonial city near Lake Nicaragua","country":"Nicaragua","buyerType":"North American retirees and remote workers; the colonial-home renovation segment is dominated by US/Canadian buyers","foreignPresence":"Commonly cited ~1,000 full-time foreigners (newer 2026 guides say 'several thousand in the broader area'); North Americans the largest group, then Spain/France/Germany/UK. Brokers claim US expats have bought and renovated ~half of the city's Spanish-colonial homes (a broker/promo claim, not verified data).","pricePoint":"Colonial homes from ~$60K; renovated foreigner-targeted homes higher; quality homes often $100K+","whyForeignersBuy":"Very low cost of living, UNESCO-grade colonial setting, territorial tax (no tax on foreign income), and unlike SJDS retains a genuine local life and Managua-elite weekend-home market","demandSignal":"Thin, segmented, buyer-favorable market: brokers estimate ~8-12 months inventory, ~90-120 days on market (renovated foreigner homes often 180+ days). Investor commentary calls it a 'lifestyle/plan-B' market with many Westerners trying to exit — i.e. real but soft foreign demand","evidenceStrength":"moderate"},{"area":"Tola / Emerald Coast (Rancho Santana, Hacienda Iguana, Guacalito de la Isla), Rivas","country":"Nicaragua","buyerType":"Higher-end international second-home/luxury and resort-investment buyers (US-led, international)","foreignPresence":"No expat-population figure, but project-level absorption is the hard signal: Rancho Santana ~2,700 acres with $100M+ invested over two decades in a 'very international' owner base; Hacienda Iguana reports 200+ lots sold, 80+ condos and 30+ houses built — concrete foreign-buyer transaction evidence inside gated resorts","pricePoint":"Beachfront $150K-$500K; high-end villas $750K-$1.5M; ultra-luxury up to ~$2.2-4.5M (Rancho Santana villas)","whyForeignersBuy":"Turnkey gated resorts with golf, beach clubs, five-star services and world-class surf at prices well below Costa Rica/Panama/Riviera Maya; fee-simple foreign ownership","demandSignal":"Sustained developer sales over 20+ years, new coastal highway cutting Managua drive time ~30-40%, and record national tourism (1.5M+ visitors, ~$1.5B revenue in 2023, longer stays/higher spend in 2025). Cash/owner-financed; data is developer-sourced so somewhat promotional","evidenceStrength":"moderate"},{"area":"Antigua Guatemala (Sacatepéquez)","country":"Guatemala","buyerType":"US/Canadian retirees + remote workers/digital nomads + second-home buyers; also Western Europeans (German, French, UK)","foreignPresence":"No published foreign-buyer-share or transaction registry exists. Country-wide hard anchor: ~9,000 Americans hold permanent residence in Guatemala (triangulated from Migration Policy Institute, US State Dept consular estimates) out of a total foreign resident stock of ~60,000-92,000 (UN migrant stock). Antigua is repeatedly named the #1 concentration point for this group; the town itself is only ~35,000 people, so even a few thousand foreigners is a visible, high-impact share. Specific count is anecdotal, not official.","pricePoint":"~$196,000-$653,000 (Q1.5M-Q5M) for typical expat homes; restored/true colonial homes run $1M+","whyForeignersBuy":"UNESCO colonial town, 'eternal spring' highland climate, ~1 hr from the international airport, strong cafe/remote-work and language-school scene, cost ~40-60% below US","demandSignal":"Foreign demand has measurably pushed prices: ~5-8% annual appreciation, a 20-30% premium over comparable Guatemala City homes, and a local price-to-income ratio (15-20x vs ~8-10x national) that insiders explicitly attribute to foreign buyers; active dedicated expat agencies, language schools and remote-work infrastructure. Buyers frame it as cheaper than San Miguel de Allende/Cartagena.","evidenceStrength":"moderate"},{"area":"Lake Atitlán – Panajachel, San Marcos La Laguna, San Pedro La Laguna, Santa Cruz/Jaibalito","country":"Guatemala","buyerType":"Wellness/yoga seekers, digital nomads, backpacker-turned-resident crowd, and a long-term retiree community; international (US/Canada/Europe) mix","foreignPresence":"One of Guatemala's two named American concentration zones (per consular/MPI-based estimates), but no hard count for the lake specifically. Presence is real and longstanding (decades-old foreign community) yet small and informal; evidenced mainly by expat-built infrastructure (retreat centers, Spanish schools, international cafes) rather than registry data.","pricePoint":"~$100,000-$200,000 for a 2BR; ~$150,000-$300,000 for a 3BR; lakefront estates higher","whyForeignersBuy":"Dramatic volcano-lake setting, very low cost of living (livable on ~$1,000/mo), Mayan cultural depth, wellness/intentional-community scene, altitude-tempered climate","demandSignal":"Active but fragmented, informal market — listings scattered across small agencies (Mayan Lake Realty, Atitlan Solutions) and Facebook groups, many deals by word of mouth. Panajachel is the most active sub-market. Demand is genuine but hard to quantify and not transparent.","evidenceStrength":"moderate"},{"area":"Santiago – Las Condes / Vitacura / Providencia / Lastarria","country":"Chile","buyerType":"North American & European professionals/executives, some retirees and investors (rental yield)","foreignPresence":"Chile hosts only ~12,000-20,000 Americans total (US State Dept registration estimate, not census). The Metropolitan Region holds ~60% of all foreign-born (Census 2024), but Chile's 1.6M foreign-born (8.8% of pop) are ~86% Latin American (Venezuela 38%, Peru 13.6%, Colombia 10.9% per INE/SERMIG 2023). US/European share is a small niche. No published municipality-level US-buyer count exists; concentration in these comunas is documented anecdotally (US Embassy is in Las Condes).","pricePoint":"$150,000-$250,000 for a 65-90 sqm apartment; premium units up to ~$4,000/sqm in Las Condes/Vitacura (avg Santiago $2,300-2,500/sqm)","whyForeignersBuy":"Safest, highest-standard comunas in the country; modern infrastructure, healthcare, walkability, and the main hub for foreign professionals and dollar earners","demandSignal":"Consistently the #1 cited expat zone across portals (Portal Inmobiliario) and expat guides; strongest absolute concentration of US/European residents; active short-term rental and executive-lease market","evidenceStrength":"moderate"},{"area":"Puerto Varas / Frutillar (Llanquihue Lake, Los Lagos)","country":"Chile","buyerType":"US & German lifestyle buyers, retirees, remote workers; vacation/second-home","foreignPresence":"The one area with a genuine, historically-rooted foreign claim: German state-led colonization (1850-1875, ~6,000 settlers) left lasting German-Chilean community in Frutillar/Puerto Varas/Puerto Octay/Osorno. Modern expat copy claims 'up to 30% foreign, primarily German and US' for Puerto Varas — widely repeated but NOT confirmed by census (no INE municipality breakdown found). Town of ~50,000 that doubles in summer.","pricePoint":"~$110,000-$200,000 for lake-area homes; rapidly appreciating","whyForeignersBuy":"Bavarian/Alpine character, volcano-and-lake scenery, temperate climate, established German heritage and outdoor lifestyle; the most 'foreign-comfortable' town outside Santiago","demandSignal":"Repeatedly named a top expat destination; dedicated foreign-facing brokers (Southern Chile Properties); documented price appreciation driven by North American/European lifestyle demand","evidenceStrength":"moderate"},{"area":"Bocas del Toro (Caribbean archipelago)","country":"Panama","buyerType":"Younger US/Canadian/European entrepreneurs, families, vacation/eco-lodge investors (skews non-retiree)","foreignPresence":"Buyer pool described as a 'limited' mix of foreign investors and expats; no population or transaction figures available. Two decades of foreign buyers but a thin, illiquid market.","pricePoint":"Homes/villas ~$280,000-$445,000; island homes from ~$169k; ocean-view lots under ~$270k; estates $1M+","whyForeignersBuy":"Caribbean island lifestyle, surfing, eco-tourism/rental business potential, low entry prices for waterfront.","demandSignal":"Steady-but-soft buyer's market; properties take months to sell (low liquidity), distance from advanced healthcare limits retiree demand. Demand described qualitatively by brokers only — closer to hype than proven hub.","evidenceStrength":"thin"},{"area":"Southern Pacific \"Costa Ballena\" — Uvita, Dominical, Ojochal","country":"Costa Rica","buyerType":"US/Canadian/European retirees, remote-work \"nomad families,\" value-seeking lifestyle buyers and long-horizon investors","foreignPresence":"Growing but smaller and newer expat community; Ojochal known as a French/European foodie enclave, Uvita a Tico-expat commercial hub. Presence is genuine but modest and almost entirely documented via developer/brokerage copy — least hard data of the major markets.","pricePoint":"Most-active foreign-buyer band $300K-$800K; finished 2BR homes $250K-$400K (~half of Tamarindo); ocean-view lots $80K-$120K; luxury estates to $2.5M","whyForeignersBuy":"30-40% cheaper than Guanacaste, extraordinary biodiversity/whale coast, larger lots and privacy, \"new Manuel Antonio\" upside narrative","demandSignal":"Brokers report ~42% YoY jumps in some Southern Zone averages and growing international community — but signals are heavily promotional; offset by inferior infrastructure, limited healthcare, long airport drives, and weak resale liquidity. Most hype-driven of the five.","evidenceStrength":"thin"},{"area":"Coffee Triangle (Eje Cafetero) – Pereira, Armenia, Manizales (esp. Pinares, Pereira)","country":"Colombia","buyerType":"Budget-focused US/Canadian retirees; 'pioneer' expats wanting authentic, low-cost living","foreignPresence":"Visible but smaller, earlier-stage expat community than Medellín — repeatedly described as 'pioneer' / 'smaller than Bogotá or Medellín.' Almost all visibility comes from International Living / Live and Invest Overseas retirement-marketing content rather than transaction or census data, so real foreign-buyer volume is unproven and likely modest.","pricePoint":"2-bed/2-bath in Pereira's Pinares from ~$75K; property values ~20–25% below Medellín; furnished expat rentals $300–$800/mo","whyForeignersBuy":"Year-round spring climate (~80°F days), very low cost of living (couple ~$1,200–$1,500/mo), cheap high-quality healthcare, accessible M-pensionado visa, undervalued real estate","demandSignal":"Heavy International Living/Live and Invest Overseas ranking coverage and small but active expat forums (Expat Exchange Eje Cafetero); limited foreigner-focused brokerage infrastructure vs Medellín — demand signal is mostly editorial hype, not portal/transaction depth","evidenceStrength":"thin"},{"area":"Bogotá – Chapinero, Usaquén, Chicó & Zona G","country":"Colombia","buyerType":"Digital nomads & working professionals; some Canadian/US/Spanish/Latin American investors and corporate relocations","foreignPresence":"Bogotá draws foreign buyers mainly from Canada, US, Spain and Latin America (broker-reported). Largest and most established expat meetup/coworking community alongside Medellín, but more renters/nomads than owner-buyers; foreign-purchase concentration weaker than Medellín or Cartagena and not officially quantified.","pricePoint":"Owner pricing varies widely; expat rentals $350–$2,000/mo; furnished Zona Rosa studio ~$550–$875/mo, lower Chapinero 1-bed $400–$550/mo","whyForeignersBuy":"Capital with cosmopolitan amenities, walkable Chapinero, dense coworking (Zona G), strongest professional/networking expat infrastructure, 4–8% rental yields","demandSignal":"Largest concentration of coworking spaces and very active Meetup/Facebook/WhatsApp nomad communities; strong long-term rental demand in Chapinero Alto/Central and Chicó — but skewed toward renting over foreign buying","evidenceStrength":"thin"},{"area":"Santa Marta – El Rodadero (+ Pozos Colorados / Playa Salguero, Taganga)","country":"Colombia","buyerType":"Vacation/second-home & STR investors; younger international buyers and digital nomads (Taganga); budget Caribbean retirees","foreignPresence":"El Rodadero named the top neighborhood for foreign buyers in Santa Marta, followed by Centro Histórico and Bello Horizonte (broker-reported, TheLatinvestor/Selling Santa Marta). Growing but small and newer expat base relative to Medellín/Cartagena; foreign-buyer share not officially measured.","pricePoint":"El Rodadero condos $60K–$300K (avg ~$171K); Pozos Colorados/Playa Salguero new-build ~$289K; Taganga entry from ~$50K","whyForeignersBuy":"Affordable Caribbean beachfront, year-round vacation-rental demand (8–10% yields), lower entry price than Cartagena, tourism growth (1.2M+ visitors/yr, intl arrivals +15–20% YoY since 2023)","demandSignal":"Dedicated foreigner-focused brokerages (Selling Santa Marta), rising international tourist arrivals, premium new-build corridor aimed at vacation investors — but reliant on STR economics now squeezed by late-2025 RNT/Airbnb registration crackdown","evidenceStrength":"thin"},{"area":"Vilcabamba (Valley of Longevity, Loja province)","country":"Ecuador","buyerType":"Health/alternative-lifestyle North American and European retirees, off-grid/homestead buyers","foreignPresence":"Tiny absolute numbers: the valley holds only ~4,200 total residents, of which the expat community (US, British, French, German, Canadian) is a few hundred at most. Visible foreign minority but no meaningful transaction or census data.","pricePoint":"Houses with land under $150k; prime acreage with water $50k-$150k+; property tax often under $100/yr","whyForeignersBuy":"'Valley of Longevity' health reputation, fertile cheap land, perfect climate, rural off-grid lifestyle, ultra-low carrying costs","demandSignal":"Heavily International Living / Expat Exchange marketing-driven. Major weakness: illiquid market with a very small buyer pool and documented difficulty reselling (forums note 80%+ of expats leave within ~2 years). Mostly hype with little hard demand proof.","evidenceStrength":"thin"},{"area":"Cayo District / San Ignacio (inland)","country":"Belize","buyerType":"Value-seeking retirees, eco/homestead and land-banking buyers, off-grid lifestyle expats","foreignPresence":"Has established inland expat communities around San Ignacio, but no firm population or foreign-buyer-share figures surfaced; presence is real but smaller and less documented than coastal hubs.","pricePoint":"2-3BR homes under $150K; land and acreage cheap relative to coast (USD)","whyForeignersBuy":"Most budget-friendly part of Belize, nature (rivers, hills, Maya ruins), farmland/eco-resort potential, English-speaking, long-term appreciation bet on tourism growth","demandSignal":"Cited by agents as a land-banking target alongside northern Ambergris; appears across expat guides and International Living, but largely guide/developer-driven narrative with little hard transaction or expat-count data","evidenceStrength":"thin"},{"area":"Hopkins (central coast)","country":"Belize","buyerType":"Retirees and second-home buyers seeking cheaper beachfront than Placencia/Ambergris","foreignPresence":"Described as attracting growing numbers of tourists and expats, but no population estimates or foreign-buyer-share data found; presence appears early-stage.","pricePoint":"More affordable than Ambergris or Placencia; modest beach-access homes (specific ranges not well documented, broadly <$400K) (USD)","whyForeignersBuy":"Affordable seaside living, Garifuna cultural draw, easy sea access and outdoor activities, freehold ownership","demandSignal":"Mentioned mainly in expat guides and realtor 'emerging area' copy; limited independent demand data, leaning on lifestyle marketing rather than proven foreign-buyer volume","evidenceStrength":"thin"},{"area":"Bariloche (Northern Patagonia – Belgrano, Melipal, Llao Llao, Arelauquen)","country":"Argentina","buyerType":"Second-home/vacation buyers, lifestyle migrants, lake-and-ski enthusiasts, some retirees","foreignPresence":"Cited as Argentina's top Patagonian secondary market with a German/Swiss heritage and an 'active expat community,' but there is NO hard expat-count or foreign-buyer-share data. Demand is driven heavily by domestic (Porteño) second-home buyers plus a minority of foreigners; near-Chilean-border rural land may trigger security-zone review. Nearly all specifics come from one commercial source (TheLatinvestor), which flags its own promotional framing.","pricePoint":"Houses ~$1,950/m2, apartments ~$2,700/m2; premium lakefront/gated $3,000-6,000+/m2; typical buy $150,000-400,000","whyForeignersBuy":"Lake/mountain/ski lifestyle, alpine-village aesthetic, stable USD prices, new airport-capacity expansion improving connectivity","demandSignal":"Listed as #4 foreign-preference market after BA/Mendoza/Córdoba; structural tourism + second-home demand — but foreign-specific demand is largely asserted, not measured (thin hard data)","evidenceStrength":"thin"},{"area":"Rio de Janeiro – Zona Sul (Ipanema, Leblon, Copacabana, Botafogo)","country":"Brazil","buyerType":"Vacation/second-home buyers, short-term-rental investors, some US/European retirees","foreignPresence":"Part of where Brazil's ~90,000 US citizens (early-2026 estimate) concentrate, alongside São Paulo and Florianópolis. No published foreign-buyer transaction share for Rio specifically; presence is real among prime Zona Sul stock but evidence is qualitative/realtor-driven. Locals flag Copacabana as name-recognition overhype.","pricePoint":"$300k–$1.5M+ for prime Ipanema/Leblon apartments; Botafogo cheaper entry","whyForeignersBuy":"Iconic beaches/scenery, 7–10% short-term-rental yields in prime spots, international amenities, global brand recognition","demandSignal":"Airbnb/STR investment demand, foreign ownership common in prime blocks, consistent expat-guide ranking — but no hard transaction data","evidenceStrength":"thin"},{"area":"São Paulo – Jardins, Itaim Bibi, Pinheiros, Vila Madalena","country":"Brazil","buyerType":"Corporate/relocation expats and rental-yield investors (international executives) rather than retirees","foreignPresence":"Cited as the largest absolute share of Brazil's ~90,000 US residents plus British/European expats, driven by corporate relocation (financial capital). But these are overwhelmingly RENTERS and relocated employees, not home buyers; no data shows meaningful foreign owner-occupier purchase share. Foreign property investment is real but institutional/yield-driven, not an expat homeowner hub.","pricePoint":"$200k–$1M+ for apartments in Jardins/Itaim Bibi; 4–6% rental yields","whyForeignersBuy":"Financial center, deepest rental market, international schools/services — investment and job relocation, not lifestyle/retirement","demandSignal":"Highest foreign investment volume nationally, strong corporate-expat rental demand — but homeowner-buyer signal is weak","evidenceStrength":"thin"},{"area":"Praia da Pipa / Natal, Rio Grande do Norte","country":"Brazil","buyerType":"European (Scandinavian, Portuguese, Italian) and Argentine second-home/retiree buyers","foreignPresence":"Famous as the case where foreigners reached ~80% of Pipa buyers — but that was the 2000–2008 charter-flight boom, which then deflated; the headline figure is historical, not current. Today described as a 'growing' but small expat community with homes still under $500k. Charter flights from Oslo/Stockholm/Gothenburg/Helsinki historically fed demand. Current foreign-buyer share is not quantified and clearly below its peak; much present-day promotion is Golden-Visa marketing.","pricePoint":"2-bed ~$200k, 3-bed ~$300k; villas under $400k–$500k marketed for R$700k NE Golden Visa","whyForeignersBuy":"Cheap NE beachfront, R$700k Golden Visa threshold, historical Nordic flight access, retiree-visa ($2k/mo income) pathway","demandSignal":"Golden-Visa-targeted listings, expat meetups in Pipa/Natal, MLSWorldwide/Holprop foreign listings — but boom-era 80% figure is dated and demand is largely hype-driven now","evidenceStrength":"thin"},{"area":"Arequipa – Yanahuara & Cayma","country":"Peru","buyerType":"Retirees and remote workers/digital nomads seeking a quieter, cheaper base than Lima; yield-focused investors","foreignPresence":"WEAK FOR WESTERNERS: Migraciones counts Arequipa among top US-expat cities, but the city's foreign influx is overwhelmingly Venezuelan/Colombian regional migrants, not home-buyers. Western expat presence is described as 'small but growing' / 'modest' with NO hard count or foreign-buyer share — largely International Living and TheLatinvestor framing.","pricePoint":"Yanahuara/Cayma ~$1,540-$2,220/m²; budget 2BR from ~$65k-$98k; 3BR Cayma condos under $150k; luxury $534k-$1.04M","whyForeignersBuy":"30-50% cheaper than Lima, colonial UNESCO old town, dry sunny climate, ~6% gross rental yields (above Lima), Colca Canyon proximity","demandSignal":"Strong rental-yield data and abundant portal listings, but flat price growth (-1% to +2% YoY) and demand narrative driven mainly by IL/portal marketing rather than transaction proof of Western buyers","evidenceStrength":"thin"},{"area":"Popoyo corridor (Tola district), Rivas — Pacific surf coast","country":"Nicaragua","buyerType":"Surf-driven foreign investors, vacation-rental buyers, lot buyers/builders (North American & European)","foreignPresence":"No expat-population data. Foreign presence inferred from broker reports of rising lot purchases, new-construction starts and foreign-buyer transaction volume in 2025-26; entirely broker/developer-sourced (Popoyo Realty, Invest Nicaragua, Life in Nica)","pricePoint":"Entry-level titled ocean-view lots through beachfront homes and modern villas; spans accessible lots up to luxury resort-grade estates","whyForeignersBuy":"World-class surf breaks plus the $400M+ Costanera highway cutting the Managua drive ~40% to ~2 hrs year-round; pitched as 'pre-appreciation' Guanacaste-style play at ~46% lower cost than Costa Rica","demandSignal":"Heavy broker marketing of a 'boom' tied to the coastal highway (first 119km phase finishing ~May 2026) and record tourism; rising new-build costs. Demand signal is real but the narrative is almost entirely from parties selling the land — discount accordingly","evidenceStrength":"thin"},{"area":"Guatemala City prime zones – Zona 10 (Zona Viva), Zona 14, Zona 15 (Vista Hermosa), Zona 16 (Ciudad Cayalá)","country":"Guatemala","buyerType":"Working professionals, diplomats, NGO/missionary staff, and a growing digital-nomad segment — NOT a retiree-driven foreign wave; buyer pool is majority domestic affluent Guatemalans","foreignPresence":"Named as the capital's expat concentration zones, but the foreign cohort here is explicitly described as working professionals/diplomats rather than home-buying retirees. No foreign-buyer-share data; the purchase market in these zones is dominated by wealthy locals, with foreigners a minority of buyers (many rent rather than buy).","pricePoint":"Condos ~$1,800-$3,600/m²; typical 2BR ~$300,000, 3BR/townhouse ~$500,000","whyForeignersBuy":"Concentration of international-standard services — 24/7-security buildings, bilingual schools, private hospitals, embassies, corporate offices, reliable infrastructure","demandSignal":"Tight premium-rental conditions and 20-30% 5-yr appreciation in Zona 14/Cayalá, plus live inventory on portals (Encuentra24, etc.). But these signals reflect mostly domestic luxury demand; the specifically-foreign home-buyer signal is weak. Pricing data largely from one marketing site (TheLatinvestor), not verified statistics.","evidenceStrength":"thin"},{"area":"Viña del Mar / Valparaíso (Pacific coast)","country":"Chile","buyerType":"Vacation/second-home buyers, remote workers, rental investors; some retirees","foreignPresence":"Valparaíso Region holds ~6.3% of Chile's foreign-born (Census 2024) but that population is overwhelmingly Latin American, not North American/European. Foreign-buyer presence here is real but documented mainly via portal listings and expat guides rather than hard nationality/transaction data. ~2 hrs from Santiago airport.","pricePoint":"~$150,000-$160,000 for a 100-110 sqm ocean-view apartment; secondary-city land $200-300/sqm","whyForeignersBuy":"Beach/resort lifestyle close to Santiago, strong short-term rental market, cultural draw (Valparaíso UNESCO old town), good infrastructure","demandSignal":"Strong holiday-rental and second-home portal activity; named the top coastal expat zone after Santiago — but signal is largely marketing/portal-driven","evidenceStrength":"thin"},{"area":"La Serena / Coquimbo (north-central coast)","country":"Chile","buyerType":"Retirees and rental investors seeking warm, sunny beach lifestyle","foreignPresence":"Frequently listed as a retiree/beach option, but there is essentially no hard foreign-buyer or expat-population data specific to La Serena. Mentions are International-Living-style 'sunny beach, lower cost' copy. No census/transaction evidence of meaningful North American/European buyer concentration.","pricePoint":"~$200,000 for a ~240 sqm house with yard near the beach; among Chile's more affordable coastal entry points","whyForeignersBuy":"Year-round sun, dry climate, lower prices than Santiago/coast-central, quieter retiree pace, vineyard/Elqui Valley proximity","demandSignal":"Recurring appearance in retiree 'best places' lists and rental-yield pitches; demand signal is almost entirely marketing/portal copy with little hard proof","evidenceStrength":"thin"}];